<template>
  <div class="space-y-6">
    <div>
      <h3 class="text-base font-semibold text-slate-800">Perfil y Rubros</h3>
      <p class="text-xs text-slate-500 mt-0.5">Gestiona el tipo de negocio y las categorías disponibles</p>
    </div>

    <!-- Primary Blueprint -->
    <div class="bg-slate-50 border border-slate-200 rounded-xl p-4">
      <p class="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Rubro Principal</p>
      <div class="flex items-center gap-3">
        <div class="w-10 h-10 rounded-lg bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-sm">
          {{ primaryBlueprint?.name?.charAt(0) || '?' }}
        </div>
        <div>
          <p class="text-sm font-medium text-slate-800">{{ primaryBlueprint?.name || 'No asignado' }}</p>
          <p class="text-[11px] text-slate-400 font-mono">{{ primaryBlueprint?.code || '—' }}</p>
        </div>
      </div>
    </div>

    <!-- Category Tree -->
    <div>
      <p class="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3">Categorías Activas</p>
      <div v-if="loadingTree" class="text-xs text-slate-400 py-4">Cargando...</div>
      <div v-else class="bg-slate-50 border border-slate-200 rounded-xl p-4 max-h-64 overflow-y-auto">
        <div v-for="cat in categoryTree" :key="cat.id" class="py-1.5">
          <div class="flex items-center gap-2">
            <span class="w-1.5 h-1.5 rounded-full bg-blue-400" />
            <span class="text-sm text-slate-700">{{ cat.name }}</span>
            <span class="text-[10px] text-slate-400 font-mono">{{ cat.code }}</span>
          </div>
          <div v-if="cat.children?.length" class="ml-6 mt-0.5 space-y-0.5">
            <p v-for="ch in cat.children" :key="ch.id" class="text-xs text-slate-500 flex items-center gap-1.5">
              <span class="w-1 h-1 rounded-full bg-slate-300" />
              {{ ch.name }}
            </p>
          </div>
        </div>
        <div v-if="!categoryTree.length" class="text-xs text-slate-400 italic">Sin categorías activas</div>
      </div>
    </div>

    <!-- Extend Blueprints -->
    <div>
      <p class="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3">Activar Otros Rubros</p>
      <div class="max-h-48 overflow-y-auto space-y-1.5">
        <label v-for="bp in blueprints" :key="bp.id" class="flex items-center gap-2.5 cursor-pointer py-1.5 px-3 rounded-lg hover:bg-slate-50 transition-colors">
          <input type="checkbox" :checked="bp.subscribed" @change="toggleBlueprint(bp)" class="w-4 h-4 rounded border-slate-300 text-blue-500 focus:ring-blue-500/30" />
          <div class="flex-1">
            <p class="text-sm text-slate-700">{{ bp.name }}</p>
            <p class="text-[10px] text-slate-400 font-mono">{{ bp.code }}</p>
          </div>
        </label>
        <div v-if="!blueprints.length" class="text-xs text-slate-400 italic py-4">Cargando rubros disponibles...</div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue';
import { useApi } from '@/composables/useApi';

const { fetchApi } = useApi();
const primaryBlueprint = ref<any>(null);
const categoryTree = ref<any[]>([]);
const blueprints = ref<any[]>([]);
const loadingTree = ref(true);

onMounted(async () => {
  try {
    const [cats, bps] = await Promise.all([
      fetchApi<any>('/api/v1/catalog/categories/?page_size=200'),
      fetchApi<any>('/api/v1/tenants/blueprints/available/'),
    ]);
    categoryTree.value = Array.isArray(cats?.results) ? cats.results : (Array.isArray(cats) ? cats : []);
    blueprints.value = Array.isArray(bps) ? bps : [];
    primaryBlueprint.value = blueprints.value.find((b: any) => b.subscribed) || null;
  } catch {} finally { loadingTree.value = false; }
});

async function toggleBlueprint(bp: any) {
  await fetchApi('/api/v1/tenants/blueprints/extend/', {
    method: 'POST', data: { business_type_id: bp.id, subscribe: !bp.subscribed },
  });
  bp.subscribed = !bp.subscribed;
}
</script>
